/* ── helpers ──────────────────────────────────────────── */

function formatBlogDate(date: string) {
  return new Intl.DateTimeFormat('en', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
    timeZone: 'UTC',
  }).format(new Date(`${date}T00:00:00Z`));
}

function getAuthorInitials(name: string) {
  return name
    .split(' ')
    .slice(0, 2)
    .map((part) => part[0]?.toUpperCase() ?? '')
    .join('');
}

const CATEGORY_TAGS: Record<string, string[]> = {
  'business-setup': ['Registration', 'Compliance', 'Tanzania', 'Business', 'Licenses'],
  operations: ['Efficiency', 'Process', 'Management', 'Growth', 'Strategy'],
  compliance: ['Regulatory', 'Legal', 'Tax', 'Reporting', 'Governance'],
};

function getTagsForCategory(categoryId?: string, categoryLabel?: string): string[] {
  if (categoryId && CATEGORY_TAGS[categoryId]) return CATEGORY_TAGS[categoryId];
  if (categoryLabel) {
    const key = categoryLabel.toLowerCase().replace(/\s+/g, '-');
    if (CATEGORY_TAGS[key]) return CATEGORY_TAGS[key];
  }
  return ['Consulting', 'Tanzania', 'Business', 'Growth', 'Strategy'];
}

/* ── sub-components ──────────────────────────────────── */

function AnimatedBackButton() {
  return (
    <motion.a
      href={routes.resources}
      className="inline-flex items-center gap-2 mb-8 text-sm font-semibold text-text-muted hover:text-accent transition-colors group"
      whileHover={{ x: -4 }}
      transition={{ type: 'spring', stiffness: 300, damping: 20 }}
    >
      <ArrowLeft className="w-4 h-4 transition-transform group-hover:-translate-x-0.5" />
      Back to Resources
    </motion.a>
  );
}

function ShareButtons({ title }: { title: string }) {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(window.location.href).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const shareUrl = typeof window !== 'undefined' ? window.location.href : '';
  const encodedTitle = encodeURIComponent(title);
  const encodedUrl = encodeURIComponent(shareUrl);

  return (
    <div className="flex items-center gap-2">
      <a
        href={`https://twitter.com/intent/tweet?text=${encodedTitle}&url=${encodedUrl}`}
        target="_blank"
        rel="noopener noreferrer"
        className="w-9 h-9 rounded-full border border-border-soft flex items-center justify-center text-text-muted hover:text-accent hover:border-accent/30 transition-colors"
        aria-label="Share on X"
      >
        <svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 24 24" aria-hidden="true">
          <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231zm-1.161 17.52h1.833L7.084 4.126H5.117z" />
        </svg>
      </a>
      <a
        href={`https://www.linkedin.com/sharing/share-offsite/?url=${encodedUrl}`}
        target="_blank"
        rel="noopener noreferrer"
        className="w-9 h-9 rounded-full border border-border-soft flex items-center justify-center text-text-muted hover:text-accent hover:border-accent/30 transition-colors"
        aria-label="Share on LinkedIn"
      >
        <svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 24 24" aria-hidden="true">
          <path d="M20.447 20.452h-3.554v-5.569c0-1.328-.027-3.037-1.852-3.037-1.853 0-2.136 1.445-2.136 2.939v5.667H9.351V9h3.414v1.561h.046c.477-.9 1.637-1.85 3.37-1.85 3.601 0 4.267 2.37 4.267 5.455v6.286zM5.337 7.433a2.062 2.062 0 01-2.063-2.065 2.064 2.064 0 112.063 2.065zm1.782 13.019H3.555V9h3.564v11.452zM22.225 0H1.771C.792 0 0 .774 0 1.729v20.542C0 23.227.792 24 1.771 24h20.451C23.2 24 24 23.227 24 22.271V1.729C24 .774 23.2 0 22.222 0h.003z" />
        </svg>
      </a>
      <button
        onClick={handleCopy}
        className="w-9 h-9 rounded-full border border-border-soft flex items-center justify-center text-text-muted hover:text-accent hover:border-accent/30 transition-colors"
        aria-label="Copy link"
      >
        {copied ? (
          <CheckCircle2 className="w-3.5 h-3.5 text-accent" />
        ) : (
          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24" aria-hidden="true">
            <path strokeLinecap="round" strokeLinejoin="round" d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" />
          </svg>
        )}
      </button>
    </div>
  );
}

function LikeButton() {
  const [liked, setLiked] = useState(false);
  return (
    <button
      onClick={() => setLiked(!liked)}
      className="flex items-center gap-1 text-text-muted hover:text-red-500 transition-colors"
      aria-label={liked ? 'Unlike' : 'Like'}
    >
      <Heart className={`w-3.5 h-3.5 ${liked ? 'fill-red-500 text-red-500' : ''}`} />
    </button>
  );
}

function NewsletterBox() {
  const [email, setEmail] = useState('');
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (email.trim()) {
      setSubmitted(true);
      setTimeout(() => {
        setSubmitted(false);
        setEmail('');
      }, 3000);
    }
  };

  return (
    <div className="p-5 rounded-2xl border border-border-soft bg-surface">
      <div className="flex items-center gap-2 mb-3">
        <Mail className="w-4 h-4 text-accent" />
        <h3 className="text-sm font-semibold text-text">Newsletter</h3>
      </div>
      <p className="text-xs text-text-muted mb-3">Get business insights delivered to your inbox.</p>
      {submitted ? (
        <div className="flex items-center gap-2 text-xs text-accent font-medium">
          <CheckCircle2 className="w-3.5 h-3.5" />
          Subscribed!
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="flex gap-2">
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="Your email"
            required
            className="flex-1 min-w-0 h-9 px-3 text-xs rounded-lg border border-border-soft bg-page text-text placeholder:text-text-soft focus:outline-none focus:ring-1 focus:ring-accent/30"
          />
          <button
            type="submit"
            className="h-9 px-3 rounded-lg bg-accent text-accent-contrast text-xs font-semibold hover:bg-accent-hover transition-colors shrink-0"
          >
            Subscribe
          </button>
        </form>
      )}
    </div>
  );
}

/* ── main component ──────────────────────────────────── */

interface ResourceArticlePageProps {
  slug: string;
}

export function ResourceArticlePage({ slug }: ResourceArticlePageProps) {
  const { data: post, isPending, error } = useBlogPost(slug);
  const { data: posts = [] } = useBlogPosts();
  const { data: resourcesPage } = usePage<ResourcesPageContent>('resources');
  useResolvedBlogSeo(post);
  const hasArticleBody = hasUsableBlogBody(post?.content);

  return (
    <LoadBoundary
      error={error}
      errorDetail="This article could not be loaded right now."
      errorTitle="Unable to load the article."
      isPending={isPending}
      isReady={Boolean(post)}
      loadingLabel="Loading article..."
    >
      {() => {
        if (!post) return null;
        return hasArticleBody ? (
          (() => {
            const article = post.content;
            if (!article) return null;
            const articleHtml = getRenderableBlogHtml(article);
            const articleSections = getRenderableBlogSections(post);
            const introText = getBlogArticleIntro(post);
            const categoryLabel = post.category?.label;
            const categoryId = post.category?.id;
            const relatedPosts = getRelatedBlogPosts(post, posts);
            const tags = getTagsForCategory(categoryId, categoryLabel);

            return (
              <section className="bg-[linear-gradient(180deg,var(--color-surface)_0%,var(--color-page)_100%)]">
                <div className="container max-w-6xl py-8 md:py-12">
                  {/* Back button */}
                  <AnimatedBackButton />

                  {/* Category badge */}
                  {categoryLabel ? (
                    <span className="inline-block px-3 py-0.5 rounded-full text-xs font-bold uppercase tracking-wider border bg-accent-soft text-accent border-accent/20 mb-4">
                      {categoryLabel}
                    </span>
                  ) : null}

                  {/* Title */}
                  <h1 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-text leading-tight mb-4">
                    {post.title}
                  </h1>

                  {/* Meta row */}
                  <div className="flex flex-wrap items-center gap-x-4 gap-y-2 text-xs sm:text-sm text-text-muted mb-8">
                    {post.author ? (
                      <span className="inline-flex items-center gap-1.5">
                        <User className="w-3.5 h-3.5" />
                        {post.author.name}
                      </span>
                    ) : null}
                    {categoryLabel ? (
                      <span className="inline-flex items-center gap-1.5">
                        <span className="px-2 py-0.5 rounded-full bg-accent-soft text-accent text-[10px] font-bold uppercase tracking-wider">
                          {categoryLabel}
                        </span>
                      </span>
                    ) : null}
                    {post.readTimeMinutes ? (
                      <span className="inline-flex items-center gap-1.5">
                        <Clock className="w-3.5 h-3.5" />
                        {post.readTimeMinutes} min read
                      </span>
                    ) : null}
                    <span className="inline-flex items-center gap-1.5">
                      <Calendar className="w-3.5 h-3.5" />
                      {formatBlogDate(post.publishedAt)}
                    </span>
                    <span className="ml-auto">
                      <LikeButton />
                    </span>
                  </div>

                  {/* Hero image */}
                  <div className="relative rounded-2xl overflow-hidden mb-10 h-[250px] sm:h-[350px] lg:h-[450px] after:absolute after:inset-0 after:bg-gradient-to-t after:from-black/10 after:to-transparent after:pointer-events-none">
                    {post.coverImageSrc ? (
                      <img
                        className="w-full h-full object-cover"
                        src={post.coverImageSrc}
                        alt={post.coverAlt ?? post.title}
                      />
                    ) : (
                      <div className="w-full h-full bg-gradient-to-br from-accent/20 via-accent-soft to-surface flex items-center justify-center">
                        <span className="text-xl sm:text-2xl font-bold text-accent/60 text-center px-4">
                          {post.mediaLabel || post.title}
                        </span>
                      </div>
                    )}
                  </div>

                  {/* 2-column layout: Article + Sidebar */}
                  <div className="grid gap-10 lg:grid-cols-[2fr_1fr]">
                    {/* ── Left column: Article body ── */}
                    <div>
                      {/* Lead paragraph / intro */}
                      {introText ? (
                        <p className="text-base sm:text-lg text-text/85 font-medium leading-relaxed mb-6">
                          {introText}
                        </p>
                      ) : null}

                      {/* Article body */}
                      {articleHtml ? (
                        <section
                          className={[
                            /* h2 */
                            '[&_h2]:text-xl [&_h2]:sm:text-2xl [&_h2]:font-semibold [&_h2]:text-text [&_h2]:mt-10 [&_h2]:mb-4',
                            /* h3 */
                            '[&_h3]:text-lg [&_h3]:font-semibold [&_h3]:text-text [&_h3]:mt-8 [&_h3]:mb-3',
                            /* p */
                            '[&_p]:text-sm [&_p]:sm:text-base [&_p]:text-text-muted [&_p]:leading-relaxed [&_p]:mb-4',
                            /* ul */
                            '[&_ul]:mb-4 [&_ul]:pl-5 [&_ul]:space-y-1.5',
                            '[&_ul_li]:text-sm [&_ul_li]:sm:text-base [&_ul_li]:text-text-muted [&_ul_li]:leading-relaxed',
                            '[&_ul_li]:marker:text-accent',
                            /* ol */
                            '[&_ol]:mb-4 [&_ol]:pl-5 [&_ol]:space-y-1.5',
                            '[&_ol_li]:text-sm [&_ol_li]:sm:text-base [&_ol_li]:text-text-muted [&_ol_li]:leading-relaxed',
                            '[&_ol_li]:marker:text-accent [&_ol_li]:marker:font-semibold',
                            /* blockquote */
                            '[&_blockquote]:my-8 [&_blockquote]:p-5 [&_blockquote]:sm:p-6 [&_blockquote]:rounded-xl [&_blockquote]:bg-accent/[0.04] [&_blockquote]:border [&_blockquote]:border-accent/15 [&_blockquote]:relative',
                            '[&_blockquote_p]:text-sm [&_blockquote_p]:sm:text-base [&_blockquote_p]:text-text-muted [&_blockquote_p]:italic [&_blockquote_p]:leading-relaxed [&_blockquote_p]:mb-0',
                            /* strong */
                            '[&_strong]:text-text [&_strong]:font-semibold',
                            /* a */
                            '[&_a]:text-accent [&_a]:underline [&_a]:underline-offset-2 [&_a]:hover:text-accent-hover [&_a]:transition-colors',
                            /* img */
                            '[&_img]:rounded-xl [&_img]:my-6 [&_img]:w-full',
                          ].join(' ')}
                          dangerouslySetInnerHTML={{ __html: articleHtml }}
                        />
                      ) : (
                        articleSections.map((section) => (
                          <section key={section.heading}>
                            <h2 className="text-xl sm:text-2xl font-semibold text-text mt-10 mb-4">
                              {section.heading}
                            </h2>
                            {section.paragraphs.map((paragraph, idx) => {
                              const isLead = idx === 0 && section === articleSections[0];
                              return (
                                <p
                                  key={paragraph}
                                  className={
                                    isLead
                                      ? 'text-base sm:text-lg text-text/85 font-medium leading-relaxed mb-4'
                                      : 'text-sm sm:text-base text-text-muted leading-relaxed mb-4'
                                  }
                                >
                                  {paragraph}
                                </p>
                              );
                            })}
                          </section>
                        ))
                      )}

                      {/* Author card at bottom of article */}
                      {post.author ? (
                        <div className="mt-10 pt-8 border-t border-border-soft">
                          <div className="flex items-center gap-4">
                            {post.author.avatarSrc ? (
                              <img
                                src={post.author.avatarSrc}
                                alt={post.author.name}
                                className="w-12 h-12 rounded-full object-cover"
                              />
                            ) : (
                              <span className="flex items-center justify-center w-12 h-12 rounded-full bg-accent-soft text-accent font-bold text-lg" aria-hidden="true">
                                {getAuthorInitials(post.author.name)}
                              </span>
                            )}
                            <div>
                              <strong className="block text-text font-semibold">{post.author.name}</strong>
                              {post.author.role ? (
                                <div className="text-sm text-text-muted">{post.author.role}</div>
                              ) : null}
                              {post.author.bio ? (
                                <p className="text-xs text-text-soft mt-1 line-clamp-2">{post.author.bio}</p>
                              ) : null}
                            </div>
                          </div>
                        </div>
                      ) : null}
                    </div>

                    {/* ── Right column: Sticky Sidebar ── */}
                    <aside className="lg:sticky lg:top-24 lg:self-start lg:max-h-[calc(100vh-7rem)] lg:overflow-y-auto sidebar-scroll space-y-6">
                      {/* Share on Social */}
                      <div>
                        <h3 className="text-xs font-bold uppercase tracking-wider text-text-soft mb-3">
                          Share on Social
                        </h3>
                        <ShareButtons title={post.title} />
                      </div>

                      {/* Tags */}
                      <div>
                        <h3 className="text-xs font-bold uppercase tracking-wider text-text-soft mb-3">
                          Tags
                        </h3>
                        <div className="flex flex-wrap gap-2">
                          {tags.map((tag) => (
                            <span
                              key={tag}
                              className="px-2.5 py-1 rounded-full text-[11px] font-semibold bg-accent-soft text-accent border border-accent/10"
                            >
                              {tag}
                            </span>
                          ))}
                        </div>
                      </div>

                      {/* Related Articles */}
                      {relatedPosts.length > 0 ? (
                        <div>
                          <h3 className="text-xs font-bold uppercase tracking-wider text-text-soft mb-3">
                            Related Articles
                          </h3>
                          <div className="space-y-3">
                            {relatedPosts.map((relatedPost) => (
                              <a
                                key={relatedPost.slug}
                                href={resourceArticlePath(relatedPost.slug)}
                                className="flex gap-3 group rounded-xl p-2 -m-2 hover:bg-accent-soft/50 transition-colors"
                              >
                                <div className="w-[70px] h-[60px] rounded-lg overflow-hidden shrink-0 bg-accent-soft/50">
                                  {relatedPost.coverImageSrc ? (
                                    <img
                                      src={relatedPost.coverImageSrc}
                                      alt={relatedPost.coverAlt ?? relatedPost.title}
                                      className="w-full h-full object-cover"
                                    />
                                  ) : (
                                    <div className="w-full h-full flex items-center justify-center text-accent/40 text-xs font-bold">
                                      <Quote className="w-4 h-4" />
                                    </div>
                                  )}
                                </div>
                                <div className="min-w-0">
                                  <h4 className="text-sm font-semibold text-text leading-snug line-clamp-2 group-hover:text-accent transition-colors">
                                    {relatedPost.title}
                                  </h4>
                                  <span className="text-[11px] text-text-soft mt-1 block">
                                    {formatBlogDate(relatedPost.publishedAt)}
                                  </span>
                                </div>
                              </a>
                            ))}
                          </div>
                        </div>
                      ) : null}

                      {/* Newsletter Box */}
                      <NewsletterBox />
                    </aside>
                  </div>

                  {/* ── CTA Banner ── */}
                  <div className="mt-16 rounded-3xl overflow-hidden min-h-[260px] sm:min-h-[300px] relative flex items-center bg-gradient-to-r from-[hsl(185,60%,26%)] via-[hsl(185,60%,26%)]/80 to-[hsl(185,60%,26%)]/40">
                    <div className="relative z-10 px-8 py-12 sm:px-12 sm:py-16 max-w-2xl">
                      <h2 className="text-2xl sm:text-3xl font-bold text-white mb-3">
                        Need Expert Business Guidance?
                      </h2>
                      <p className="text-white/80 text-sm sm:text-base leading-relaxed mb-6">
                        Our team of experienced consultants is ready to help you navigate
                        Tanzania&apos;s business landscape with confidence and clarity.
                      </p>
                      <div className="flex flex-wrap gap-3">
                        <a
                          href={routes.contact}
                          className="inline-flex items-center gap-2 h-11 px-6 rounded-full bg-white text-[hsl(185,60%,26%)] font-bold text-sm hover:bg-white/90 transition-colors"
                        >
                          Contact Us
                          <ArrowRight className="w-4 h-4" />
                        </a>
                        <a
                          href="tel:+255222700061"
                          className="inline-flex items-center gap-2 h-11 px-6 rounded-full border-2 border-white/30 text-white font-bold text-sm hover:bg-white/10 transition-colors"
                        >
                          <Phone className="w-4 h-4" />
                          Call Us Now
                        </a>
                      </div>
                    </div>
                  </div>
                </div>
              </section>
            );
          })()
        ) : (
          <ErrorMessage
            detail="This article is missing its published body content."
            title="Article content is unavailable."
          />
        );
      }}
    </LoadBoundary>
  );
}
